import xml.etree.ElementTree as ET

def parse_xml_to_dict(filename):
    tree = ET.parse(filename)
    root = tree.getroot()
    settings = {}

    for element in root:
        key = element.tag
        value = ""

        for subelement in element:
            value += str(subelement)

        settings[key] = value

    return settings